Bash(powershell -Command "
\\$ProgressPreference = 'SilentlyContinue';
\\$url = 'https://github.com/coreybutler/nvm-windows/releases/download/1.2.2/nvm-setup.exe';
\\$out = \\"\\$env:TEMP\\\\nvm-setup.exe\\";
try {
    Invoke-WebRequest -Uri \\$url -OutFile \\$out -UseBasicParsing -TimeoutSec 60;
    Write-Host 'Downloaded to' \\$out;
    \(Get-Item \\$out\).Length
} catch {
    Write-Host 'Error:' \\$_.Exception.Message
}
")

Bash(powershell -Command "
\\$nvmPath = \\"\\$env:APPDATA\\\\nvm\\";
if \(Test-Path \\"\\$nvmPath\\\\nvm.exe\\"\) {
    & \\"\\$nvmPath\\\\nvm.exe\\" version
} else {
    Write-Host 'nvm not found at' \\$nvmPath;
    Get-ChildItem 'C:\\\\Users\\\\60273\\\\AppData\\\\Roaming\\\\nvm' -ErrorAction SilentlyContinue | Select-Object Name
}
")
